mapper.select:
SELECT c.id, c.category_id, cc.name AS category_name, c.title, c.subtitle, c.cover_image, c.description, c.teacher_name, c.price, c.registration_fee, c.status, c.create_time, c.update_time FROM course c LEFT JOIN course_category cc ON c.category_id = cc.id WHERE c.deleted = 0
AND c.category_id = #{categoryId}
AND c.title LIKE CONCAT('%', #{keyword}, '%')
AND c.status = #{status}
ORDER BY c.create_time DESC
